public int countStarsExceptBetweenPair(String s) {
    int count = 0;
    int pipeCount = 0;

    for (char c : s.toCharArray()) {
        if (c == '|') {
            pipeCount++;
        } else if (c == '*' && pipeCount % 2 == 0) {
            count++;
        }
    }

    return count;
}
```


